begin;
delete from public.cards;
delete from public.decks where slug = 'karaoke';
update public.decks set slug='start', name='{"it": "Start", "en": "Start"}', description='{"it": "Per rompere il ghiaccio e scaldare il gruppo", "en": "Break the ice and warm up the group"}', intensity=1, is_premium=false, min_players=2, sort_order=1 where slug='start';
update public.decks set slug='spicy', name='{"it": "Spicy", "en": "Spicy"}', description='{"it": "Sfacciato e civettuolo: domande pungenti e sfide", "en": "Cheeky and flirty: bold questions and dares"}', intensity=2, is_premium=false, min_players=2, sort_order=2 where slug='mood';
update public.decks set slug='deep', name='{"it": "Deep", "en": "Deep"}', description='{"it": "Domande vere e confessioni profonde", "en": "Real questions and deep confessions"}', intensity=2, is_premium=false, min_players=2, sort_order=3 where slug='profondo';
update public.decks set slug='hot', name='{"it": "Hot", "en": "Hot"}', description='{"it": "Piccante e sensuale. Solo per adulti", "en": "Spicy and sensual. Adults only"}', intensity=3, is_premium=false, min_players=2, sort_order=4 where slug='hot';
update public.decks set slug='coppia', name='{"it": "Coppia", "en": "Couple"}', description='{"it": "Pensato per chi gioca in coppia", "en": "Made for couples"}', intensity=2, is_premium=false, min_players=2, sort_order=5 where slug='coppia';
update public.decks set slug='streap', name='{"it": "Streap", "en": "Streap"}', description='{"it": "Sfide bollenti in stile striptease. Sbloccalo per osare", "en": "Red-hot striptease dares. Unlock to dare"}', intensity=3, is_premium=true, min_players=2, sort_order=6 where slug='ambiente';

