  ('coppia','domanda','{"it": "{player}, qual e'' la fantasia romantica che vorresti realizzare con {player2}? Se non lo dici, bevi due WOOH.", "en": "{player}, what''s the romantic fantasy you''d love to fulfill with {player2}? If you don''t say it, drink two WOOH."}',2,false,2,13),
  ('coppia','azione','{"it": "{player} accarezza i capelli di {player2} per 15 secondi mentre lo guarda negli occhi. Se ridi, bevi.", "en": "{player} strokes {player2}''s hair for 15 seconds while looking into their eyes. If you laugh, drink."}',2,false,2,14),
  ('coppia','io_non_ho_mai','{"it": "Io non ho mai mandato un messaggio piccante a {player2}. Chi l''ha fatto beve.", "en": "I have never sent a spicy text to {player2}. Whoever has, drinks."}',2,false,2,15),
  ('coppia','domanda','{"it": "{player}, qual e'' il ricordo piu'' bello che hai con {player2}? Raccontalo. Se lo liquidi in una frase, bevi.", "en": "{player}, what''s your favorite memory with {player2}? Tell it. If you dismiss it in one sentence, drink."}',2,false,2,16),
  ('coppia','azione','{"it": "{player} e {player2} si scambiano un complimento a turno per 30 secondi. Il primo che resta senza idee beve.", "en": "{player} and {player2} exchange compliments back and forth for 30 seconds. The first to run out of ideas drinks."}',3,false,2,17),
  ('coppia','azione','{"it": "{player} sussurra a {player2} cosa vorrebbe fare con lui dopo questa partita. Se arrossisci, bevi.", "en": "{player} whispers to {player2} what they''d like to do after this game. If you blush, drink."}',3,false,2,18),
  ('coppia','domanda','{"it": "{player}, qual e'' la parte del corpo di {player2} che preferisci e perche''? Se non rispondi, bevi.", "en": "{player}, which part of {player2}''s body is your favorite and why? If you don''t answer, drink."}',2,false,2,19),
  ('coppia','azione','{"it": "{player} guarda {player2} e gli fa l''occhiolino piu'' sexy che riesce. Se {player2} ride, beve {player2}.", "en": "{player} looks at {player2} and gives the sexiest wink they can. If {player2} laughs, {player2} drinks."}',2,false,2,20),
  ('coppia','regola','{"it": "Per i prossimi tre giri, {player} e {player2} non possono chiamarsi per nome ma solo con un nomignolo dolce. Chi sbaglia beve.", "en": "For the next three rounds, {player} and {player2} can only call each other by a sweet nickname, not their names. Whoever slips drinks."}',2,true,2,21),
  ('coppia','io_non_ho_mai','{"it": "Io non ho mai pensato a {player2} mentre ascoltavo una canzone d''amore. Chi l''ha fatto beve.", "en": "I have never thought of {player2} while listening to a love song. Whoever has, drinks."}',2,false,2,22),
  ('coppia','azione','{"it": "{player} e {player2} si mettono fronte a fronte e si imitano a vicenda per 20 secondi. Il meno bravo beve.", "en": "{player} and {player2} face each other and mimic one another for 20 seconds. The worse one drinks."}',2,false,2,23),
  ('coppia','domanda','{"it": "{player}, se dovessi organizzare l''appuntamento perfetto per {player2}, come sarebbe? Se non hai idee, bevi.", "en": "{player}, if you had to plan the perfect date for {player2}, what would it be? If you have no ideas, drink."}',2,false,2,24),
  ('coppia','azione','{"it": "{player} bacia {player2} sulla guancia o sulla fronte, a scelta. Se ti tiri indietro, bevi due WOOH.", "en": "{player} kisses {player2} on the cheek or forehead, your choice. If you pull back, drink two WOOH."}',2,false,2,25),
  ('coppia','domanda','{"it": "{player}, qual e'' la cosa piu'' romantica che {player2} ha fatto per te? Se non te la ricordi, bevi.", "en": "{player}, what''s the most romantic thing {player2} has ever done for you? If you can''t recall, drink."}',2,false,2,26),
  ('coppia','azione','{"it": "{player} prende il viso di {player2} tra le mani e lo guarda in silenzio per 10 secondi. Chi ride beve.", "en": "{player} holds {player2}''s face in their hands and gazes silently for 10 seconds. Whoever laughs drinks."}',2,false,2,27),
  ('coppia','io_non_ho_mai','{"it": "Io non ho mai sognato {player2} di notte. Chi l''ha fatto beve e racconta il sogno.", "en": "I have never dreamed about {player2} at night. Whoever has, drinks and tells the dream."}',2,false,2,28),
  ('coppia','domanda','{"it": "{player}, completa la frase guardando {player2}: ''Quando ti vedo mi viene voglia di...''. Se non finisci, bevi.", "en": "{player}, finish the sentence while looking at {player2}: ''When I see you I feel like...''. If you don''t finish, drink."}',3,false,2,29),
  ('coppia','azione','{"it": "{player} e {player2} appoggiano le fronti una contro l''altra e respirano insieme per 15 secondi. Chi ride beve.", "en": "{player} and {player2} press their foreheads together and breathe together for 15 seconds. Whoever laughs drinks."}',2,false,2,30),
  ('coppia','wooh','{"it": "{player} e {player2} brindano guardandosi negli occhi e bevono insieme un WOOH all''amore. Se distogliete lo sguardo, due WOOH.", "en": "{player} and {player2} toast looking into each other''s eyes and drink one WOOH to love. If you look away, two WOOH."}',2,false,2,31),
  ('coppia','domanda','{"it": "{player}, qual e'' il profumo o il dettaglio di {player2} che ti fa girare la testa? Se non rispondi, bevi.", "en": "{player}, what scent or detail of {player2} makes your head spin? If you don''t answer, drink."}',2,false,2,32),
  ('coppia','azione','{"it": "{player} scrive con il dito sulla schiena di {player2} una parola dolce e {player2} deve indovinarla. Se sbaglia, beve {player2}.", "en": "{player} writes a sweet word on {player2}''s back with a finger and {player2} must guess it. If wrong, {player2} drinks."}',2,false,2,33),
  ('coppia','io_non_ho_mai','{"it": "Io non ho mai avuto le farfalle nello stomaco per {player2}. Chi le ha avute beve.", "en": "I have never had butterflies for {player2}. Whoever has, drinks."}',2,false,2,34),
  ('coppia','domanda','{"it": "{player}, dove vorresti che {player2} ti baciasse adesso? Indicalo. Se non rispondi, bevi due WOOH.", "en": "{player}, where would you want {player2} to kiss you right now? Point to it. If you don''t answer, drink two WOOH."}',3,false,2,35),
  ('coppia','azione','{"it": "{player} e {player2} si dichiarano amore eterno con la voce piu'' drammatica possibile, come in una telenovela. Il meno teatrale beve.", "en": "{player} and {player2} declare eternal love in the most dramatic voice possible, like a soap opera. The less theatrical one drinks."}',2,false,2,36),
  ('coppia','domanda','{"it": "{player}, raccontaci il primo bacio con {player2}. Se ne salti i dettagli, bevi.", "en": "{player}, tell us about your first kiss with {player2}. If you skip the details, drink."}',2,false,2,37),
  ('coppia','azione','{"it": "{player} massaggia le spalle di {player2} per 30 secondi. Se ti fermi prima, bevi.", "en": "{player} massages {player2}''s shoulders for 30 seconds. If you stop early, drink."}',2,false,2,38),
  ('coppia','io_non_ho_mai','{"it": "Io non ho mai immaginato il futuro insieme a {player2}. Chi l''ha fatto beve e dice cosa ha immaginato.", "en": "I have never imagined a future with {player2}. Whoever has, drinks and says what they pictured."}',2,false,2,39),
  ('coppia','domanda','{"it": "{player}, qual e'' la canzone che ti ricorda {player2}? Cantane un pezzo. Se non la canti, bevi.", "en": "{player}, what song reminds you of {player2}? Sing a bit of it. If you don''t sing, drink."}',2,false,2,40),
  ('coppia','azione','{"it": "{player} guarda {player2} e gli dice ''ti voglio'' in tre lingue diverse. Per ogni lingua che manca, un WOOH.", "en": "{player} looks at {player2} and says ''I want you'' in three different languages. For each missing language, one WOOH."}',3,false,2,41),
  ('coppia','regola','{"it": "Fino alla fine del giro, {player} e {player2} devono restare seduti vicinissimi, in contatto. Chi si allontana beve.", "en": "Until the end of the round, {player} and {player2} must stay seated very close, in contact. Whoever pulls away drinks."}',2,true,2,42),
  ('coppia','domanda','{"it": "{player}, cosa indosseresti per fare una sorpresa romantica a {player2}? Se non lo dici, bevi.", "en": "{player}, what would you wear to give {player2} a romantic surprise? If you don''t say, drink."}',2,false,2,43),
  ('coppia','azione','{"it": "{player} e {player2} si scambiano un bacio sulla mano contemporaneamente, sincronizzati. Se sbagliate il tempo, bevete entrambi.", "en": "{player} and {player2} kiss each other''s hand at the same time, in sync. If your timing''s off, you both drink."}',2,false,2,44),
  ('coppia','io_non_ho_mai','{"it": "Io non ho mai arrossito per qualcosa che mi ha detto {player2}. Chi e'' arrossito beve.", "en": "I have never blushed at something {player2} said. Whoever blushed, drinks."}',2,false,2,45),
  ('coppia','domanda','{"it": "{player}, qual e'' il soprannome segreto che daresti a {player2}? Diglielo a voce alta. Se non lo fai, bevi.", "en": "{player}, what secret nickname would you give {player2}? Say it out loud. If you don''t, drink."}',2,false,2,46),
  ('coppia','azione','{"it": "{player} sussurra all''orecchio di {player2} una promessa per la prossima notte insieme. Se ti vergogni, bevi.", "en": "{player} whispers in {player2}''s ear a promise for your next night together. If you get shy, drink."}',3,false,2,47),
  ('coppia','domanda','{"it": "{player}, se {player2} fosse un piatto, quale sarebbe e perche'' lo divoreresti? Se non rispondi, bevi.", "en": "{player}, if {player2} were a dish, which one and why would you devour it? If you don''t answer, drink."}',2,false,2,48),
  ('coppia','azione','{"it": "{player} e {player2} mimano la loro coppia preferita di un film. Gli altri devono indovinare. Se nessuno indovina, bevete entrambi.", "en": "{player} and {player2} act out their favorite movie couple. The others guess. If no one gets it, you both drink."}',2,false,2,49),
  ('coppia','wooh','{"it": "{player} fa un brindisi dedicato a {player2}, poi entrambi bevono un WOOH. Se il brindisi non strappa un sorriso a {player2}, {player} ne beve un altro.", "en": "{player} makes a toast dedicated to {player2}, then both drink one WOOH. If the toast doesn''t make {player2} smile, {player} drinks another."}',2,false,2,50),
  ('streap','regola','{"it": "Regola d''oro STREAP: chiunque può passare una carta bevendo, sempre e senza spiegazioni. Nessuno deve giustificarsi.", "en": "STREAP golden rule: anyone can skip a card by drinking, always and without explaining. No one owes a justification."}',5,true,0,1),
  ('streap','regola','{"it": "Si resta sempre almeno in intimo: niente nudità totale, mai. Questo mazzo è giocoso e provocante, non spinto.", "en": "You always stay at least in your underwear: never full nudity. This deck is playful and teasing, not explicit."}',5,true,0,2),
  ('streap','regola','{"it": "Nessun contatto fisico senza un sì esplicito della persona coinvolta. Se manca il sì, si beve e si passa.", "en": "No physical contact without an explicit yes from the person involved. No yes means you drink and move on."}',5,true,0,3),
  ('streap','azione','{"it": "{player} si toglie le scarpe con stile, come fosse l''inizio di uno show. Applausi obbligatori.", "en": "{player} takes off their shoes with style, as if it were the start of a show. Applause required."}',4,false,1,4),
